/**
 * A sealed envelope this node is muling for someone else (DESIGN.md §5.3
 * carry queue): a foreign envelope we couldn't open (so it isn't for us) but
 * hold on to, to hand to its recipient when we next meet them. These are the
 * §6.4 public-header fields plus the opaque sealed blob -- everything needed
 * to reconstruct the exact `0x02` frame for onward delivery (see
 * [`crate::encode_envelope_frame`]). The internal eviction bookkeeping
 * (is-family, received-at, size) is deliberately *not* on this record: it's
 * an implementation detail of the store's budget enforcement, not something
 * the transport layer needs when it pulls an envelope back out to send.
 */
public struct CarriedEnvelope {
    public var msgId: Data
    public var hopTtl: UInt8
    public var expiry: Int64
    public var recipientHint: Data
    public var sealed: Data

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(msgId: Data, hopTtl: UInt8, expiry: Int64, recipientHint: Data, sealed: Data) {
        self.msgId = msgId
        self.hopTtl = hopTtl
        self.expiry = expiry
        self.recipientHint = recipientHint
        self.sealed = sealed
    }
}



extension CarriedEnvelope: Equatable, Hashable {
    public static func ==(lhs: CarriedEnvelope, rhs: CarriedEnvelope) -> Bool {
        if lhs.msgId != rhs.msgId {
            return false
        }
        if lhs.hopTtl != rhs.hopTtl {
            return false
        }
        if lhs.expiry != rhs.expiry {
            return false
        }
        if lhs.recipientHint != rhs.recipientHint {
            return false
        }
        if lhs.sealed != rhs.sealed {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(msgId)
        hasher.combine(hopTtl)
        hasher.combine(expiry)
        hasher.combine(recipientHint)
        hasher.combine(sealed)
    }
}


